# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

from machine import Pin
from time import sleep
import dht
from umqtt.simple import MQTTClient

client_id = "esp32_temp_sensor"
broker_ip = "192.168.1.10"
topic = "sensors/temp"

sensor = dht.DHT22(Pin(4))
client = MQTTClient(client_id, broker_ip)

def connect_to_mqtt():
    try:
        client.connect()
        print("Connected to MQTT Broker")
    except Exception as e:
        print("Failed to connect to MQTT Broker")
        print(e)
        return False
    return True

def publish_temperature():
    try:
        sensor.measure()
        temp = sensor.temperature()
        client.publish(topic, str(temp))
        print(f"Published temperature: {temp} to {topic}")
    except OSError as e:
        print("Failed to read sensor or publish data")
        print(e)

if connect_to_mqtt():
    try:
        while True:
            publish_temperature()
            sleep(60)
    finally:
        client.disconnect()